import{_ as e,o as l,c as a,a3 as i}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"🔧 上下文管道 (Context Pipeline) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/index.md","filePath":"user-guide/tools/llm-chat/context-pipeline/index.md","lastUpdated":1778239080000}'),n={name:"user-guide/tools/llm-chat/context-pipeline/index.md"};function o(r,t,s,d,h,p){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="🔧-上下文管道-context-pipeline-概览" tabindex="-1">🔧 上下文管道 (Context Pipeline) 概览 <a class="header-anchor" href="#🔧-上下文管道-context-pipeline-概览" aria-label="Permalink to &quot;🔧 上下文管道 (Context Pipeline) 概览&quot;">​</a></h1><p>上下文管道 (Context Pipeline) 是 LLM Chat 的核心处理引擎——它负责将原始消息、预设、世界书、知识库等碎片化内容，<strong>按照预设的逻辑顺序组装成最终发送给 LLM 的请求上下文</strong>。</p><h2 id="为什么需要管道" tabindex="-1">为什么需要管道？ <a class="header-anchor" href="#为什么需要管道" aria-label="Permalink to &quot;为什么需要管道？&quot;">​</a></h2><p>一次高质量的 AI 对话请求通常涉及多个复杂的处理步骤，例如：</p><ul><li>注入 Agent 的系统提示词。</li><li>匹配并注入世界书条目或知识库片段。</li><li>应用用户自定义的正则替换规则。</li><li>展开动态宏（如当前时间、变量值）。</li><li>确保总 Token 数不超过模型限制。</li></ul><p>上下文管道通过<strong>可编排的处理器序列</strong>来管理这些步骤，每个处理器专注于一个核心职责，确保了处理过程的透明和可调试性。</p><h2 id="管道架构" tabindex="-1">管道架构 <a class="header-anchor" href="#管道架构" aria-label="Permalink to &quot;管道架构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始会话数据 → [处理器 A] → [处理器 B] → [处理器 C] ... → 最终 API 请求</span></span></code></pre></div><p>系统允许你在聊天设置中灵活配置管道：</p><ul><li><strong>独立开关</strong>: 每个处理器都可以单独开启或关闭。</li><li><strong>顺序调整</strong>: 拖拽改变处理器的执行顺序，以应对特殊的上下文逻辑需求。</li><li><strong>实时监控</strong>: 通过 <a href="./analyzer">上下文分析器</a> 实时观察每个处理器的输入与输出。</li></ul><h2 id="核心处理器分类" tabindex="-1">核心处理器分类 <a class="header-anchor" href="#核心处理器分类" aria-label="Permalink to &quot;核心处理器分类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">分类</th><th style="text-align:left;">处理器示例</th><th style="text-align:left;">职责</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>基础加载</strong></td><td style="text-align:left;">Session Loader, Assembler</td><td style="text-align:left;">加载历史、组装预设消息</td></tr><tr><td style="text-align:left;"><strong>内容增强</strong></td><td style="text-align:left;">Worldbook, Knowledge, Transcription</td><td style="text-align:left;">注入世界书、RAG 检索、附件转写</td></tr><tr><td style="text-align:left;"><strong>文本处理</strong></td><td style="text-align:left;">Regex, Macro, Variable</td><td style="text-align:left;">正则清洗、宏展开、变量状态更新</td></tr><tr><td style="text-align:left;"><strong>预算与格式</strong></td><td style="text-align:left;">Token Limiter, Formatter</td><td style="text-align:left;">Token 裁剪、API 协议适配</td></tr></tbody></table><hr><h3 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h3><ul><li><a href="./processors">处理器详解与执行顺序</a></li><li><a href="./knowledge-processor">RAG 知识库检索配置</a></li><li><a href="./token-management">Token 预算与预算管理</a></li><li><a href="./analyzer">上下文分析器指南</a></li></ul>',15)])])}const x=e(n,[["render",o]]);export{c as __pageData,x as default};
